const viewer = document.getElementById('viewer');
const select = document.getElementById('which');
const SOURCES = {
  sc: "data:model/gltf-binary;base64,",
  bcc:"data:model/gltf-binary;base64,",
  fcc:"data:model/gltf-binary;base64,"
,
  corte:"data:model/gltf-binary;base64,"
};

select.addEventListener('change', ()=>{ viewer.src = SOURCES[select.value]; });
document.getElementById('reset').addEventListener('click',()=>{
  viewer.cameraOrbit = 'auto auto auto';
  viewer.cameraTarget = '0m 0m 0m';
});


select.addEventListener('change', ()=>{ viewer.src = SOURCES[select.value]; });

viewer.addEventListener('load', ()=>{
  viewer.cameraTarget = 'auto';
  viewer.cameraOrbit = '45deg 65deg auto';
  viewer.jumpCameraToGoal();
});

document.getElementById('reset').addEventListener('click', ()=>{
  viewer.cameraOrbit = 'auto auto auto';
  viewer.cameraTarget = '0m 0m 0m';
});
